        zerosTotal = s.count('0')
        onesTotal = s.count('1')
        best = 0
        for i in range(n):
            ones = 0
            zeros = 0
            for j in range(i, n):
                if s[j] == '1':
                    ones += 1
                else:
                    zeros += 1
                diff = ones - zeros
                length = j - i + 1
                if diff == 0:
                    best = max(best, length)
                elif diff == 2:
                    if zerosTotal - zeros >= 1:
                        best = max(best, length)
                elif diff == -2:
                    if onesTotal - ones >= 1:
                        best = max(best, length)
        return best

