from bisect import bisect_left, insort
class Solution:
    def longestBalanced(self, s: str) -> int:
        n = len(s)
        zerosTotal = s.count('0')
        onesTotal = s.count('1')
        P = [0] * (n + 1)
        for i in range(n):
            P[i + 1] = P[i] + (1 if s[i] == '1' else -1)

        def longest_with_diff(target, cap):
            best = 0
            groups = {}
            for j in range(n + 1):
                need = P[j] - target
                if need in groups:
                    lst = groups[need]
                    lo = j - cap
                    idx = bisect_left(lst, lo)
                    if idx < len(lst):
                        i = lst[idx]
                        if j - i > best:
                            best = j - i
                val = P[j]
                if val not in groups:
                    groups[val] = []
                insort(groups[val], j)
            return best

        d0 = longest_with_diff(0, n)
        d_pos2 = longest_with_diff(2, 2 * zerosTotal + 1)
        d_neg2 = longest_with_diff(-2, 2 * onesTotal + 1)
        return max(d0, d_pos2, d_neg2)

