var longestBalanced = function(s) {
    const n = s.length;
    let zerosTotal = 0, onesTotal = 0;
    for (const c of s) { if (c === '0') zerosTotal++; else onesTotal++; }
    const P = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) P[i + 1] = P[i] + (s[i] === '1' ? 1 : -1);

    function longestWithDiff(target, cap) {
        let best = 0;
        const groups = new Map();
        for (let j = 0; j <= n; j++) {
            const need = P[j] - target;
            if (groups.has(need)) {
                const lst = groups.get(need);
                const lo = j - cap;
                let lowIdx = 0, high = lst.length;
                while (lowIdx < high) {
                    const mid = (lowIdx + high) >> 1;
                    if (lst[mid] < lo) lowIdx = mid + 1; else high = mid;
                }
                if (lowIdx < lst.length) {
                    const i = lst[lowIdx];
                    if (j - i > best) best = j - i;
                }
            }
            const val = P[j];
            if (!groups.has(val)) groups.set(val, []);
            groups.get(val).push(j);
        }
        return best;
    }

    const d0 = longestWithDiff(0, n);
    const dPos2 = longestWithDiff(2, 2 * zerosTotal + 1);
    const dNeg2 = longestWithDiff(-2, 2 * onesTotal + 1);
    return Math.max(d0, dPos2, dNeg2);
};
